class EventEmitter:
    def __init__(self):
        # {event: [callback1, callback2, ...] }
        self._listeners = {}
        # {event: [(callback, is_once), ...] } 
        # Storing flags for one-time events might be complex. Let's track them separately.
        # Using a unique ID or tuple (function, one_shot) might work better
        self._listeners = {}
        self._once_listeners = {} # {event: [(callback, reference), ...] }

    def __init__(self):
        # Structure: {event_name: [list of callbacks] }
        self._listeners = {}
        # Structure: {event_name: [list of unique references for one-time calls] }
        self._once_listeners = {} 

    def on(self, event, callback): 
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)

    def off(self, event, callback): 
        if event in self._listeners:
            try: 
                self._listeners[event].remove(callback)
            except ValueError:
                pass # Listener wasn't attached

    def once(self, event, callback):
        # Add to normal listeners and immediately queue for one-time handling.
        if event not in self._once_listeners:
            self._once_listeners[event] = []

        # The unique list must contain the callable object itself
        # We add it to both lists for consistency, but only use once logic on _once_listeners
        self._once_listeners[event].append(callback)
        self.on(event, callback) # Ensure it's also available via .off()

    def emit(self, event, *args): 
        # 1. Handle standard listeners (including initial calls from once/on that haven't fired yet)
        if event in self._listeners:
            callbacks = list(self._listeners[event])
            for callback in callbacks:
                try: 
                    callback(*args)
                except Exception as e:
                    # In real world, we might want better error handling here
                    pass

        # 2. Handle one-time listeners (must iterate over a copy because removal happens inside)
        if event in self._once_listeners:
            callbacks = list(self._once_listeners[event])
            fired_indices = []
            for i, callback in enumerate(callbacks):
                try:
                    callback(*args)
                    # Mark this execution instance as done
                    fired_indices.append(i)
                except Exception:
                    pass # Swallow errors from callbacks

            if fired_indices:
                # Remove the executed listeners safely backwards to maintain indices
                remaining = list(self._once_listeners[event])[:]
                for i in reversed(fired_indices): 
                   del remaining[i]
                 self._once_listeners[event] = remaining
                if not self._once_listeners[event]:
                    # Clean up the event key if all once listeners are removed
                    del self._once_listeners[event]
